  const [loading, setLoading] = useState(false);

  const handleUnlock = async () => {
    setLoading(true);
    try {
      const available = await checkRoomAvailability(room.id);
      if (!available) {
        alert("Cette chambre n'est plus disponible.");
        setLoading(false);
        return;
      }

