        onUnlocked && onUnlocked(room.id);
      } else {
        alert("Paiement échoué.");
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white p-4 rounded shadow">
      <img src={room.photos?.[0] || ""} className="w-full h-40 object-cover rounded mb-2" />
      <h3 className="font-semibold">{room.title}</h3>
