function antiNumInfo(message: string): boolean {
  if (!message) return false;

  const normalized = message
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9 ]/g, " ");

  // 1. Détection de patterns de numéros
  const phoneRegex = /(\d[\s-]*){8,15}/g; // 8 à 15 chiffres, même espacés
  if (phoneRegex.test(normalized)) return true;

  // 2. Détection de chiffres écrits en lettres
  const numberWords = [
    "zero","un","une","deux","trois","quatre","cinq","six","sept","huit","neuf",
    "dix","onze","douze","treize","quatorze","quinze","seize","vingt",
    "trente","quarante","cinquante","soixante","soixante dix",
    "quatre vingt","quatre vingt dix"
  ];
  const words = normalized.split(/\s+/);
  let countWords = 0;

  for (const w of words) {
    if (numberWords.includes(w)) countWords++;
  }

  if (countWords >= 3) return true; // trois mots chiffres → suspect

  // 3. Emails
  const emailRegex =
    /[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/;
  if (emailRegex.test(normalized)) return true;

  // 4. Localisations trop précises
  const locationTerms = [
    "quartier","immeuble","derriere","devant","a cote",
    "rue","porte","batiment","gps","localisation","coordonnees"
  ];
  for (const t of locationTerms) {
    if (normalized.includes(t)) return true;
  }

  return false;
}

