/**
 * SERVICE DE SÉCURITÉ (SIMULATION BACKEND)
 * Ce fichier contient la logique stricte pour empêcher l'échange de coordonnées.
 */

export function antiNumInfo(message: string): boolean {
  if (!message) return false;

  // Normalisation : minuscule, sans accent, caractères spéciaux remplacés par espace
  const normalized = message
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "") // Enlève les accents
    .replace(/[^a-z0-9 ]/g, " ");    // Garde uniquement lettres et chiffres

  // 1. Détection de patterns de numéros (Regex stricte)
  // Détecte une suite de 8 chiffres ou plus, même séparés par des espaces, points, tirets
  // Ex: 07 07 07 07, 0.7.0.7...
  const phoneRegex = /(\d\s*[-.]?\s*){8,}/;
  if (phoneRegex.test(message)) return true;

  // 2. Détection de chiffres écrits en lettres
  const numberWords = [
    "zero", "un", "une", "deux", "trois", "quatre", "cinq", "six", "sept", "huit", "neuf",
    "dix", "onze", "douze", "treize", "quatorze", "quinze", "seize", "vingt",
    "trente", "quarante", "cinquante", "soixante", "soixante dix", "soixante-dix",
    "quatre vingt", "quatre-vingt", "quatre vingt dix", "cent", "mille"
  ];

  const words = normalized.split(/\s+/);
  let countWords = 0;

  for (const w of words) {
    if (numberWords.includes(w)) countWords++;
  }

  // Seuil de tolérance très bas : 3 mots chiffres = blocage
  if (countWords >= 3) return true;

  // 3. Emails
  const emailRegex = /[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/;
  if (emailRegex.test(normalized.replace(/\s/g, ''))) return true; // On enlève les espaces pour check email caché

  // 4. Localisations trop précises & Mots clés interdits
  const locationTerms = [
    "quartier", "immeuble", "derriere", "devant", "a cote", "cote",
    "rue", "porte", "batiment", "gps", "localisation", "coordonnees",
    "villa", "carrefour", "pharmacie", "ecole", "college", "lycee",
    "maison", "etage", "appeler", "appel", "numero", "contact", "joindre"
  ];

  for (const t of locationTerms) {
    // Vérification mot entier ou phrase
    if (normalized.includes(` ${t} `) || normalized.startsWith(`${t} `) || normalized.endsWith(` ${t}`)) {
        return true;
    }
  }

  return false;
}
