Ajout de l'onglet et de la fonctionnalité "ZONE BETA" dans le tableau de bord.

```tsx
import React, { useState } from 'react';
import { Transaction, UserProfile, UserRole, ProFeedback, ClientReview, InternshipRequest, InternshipStatus } from '../types';
import { Wallet, TrendingUp, PieChart, Building2, Download, Users, CheckCircle, XCircle, Search, Trophy, MessageSquare, Star, MessageCircle, Filter, GraduationCap, FileText, Send, Mail, AlertTriangle, TestTube, Zap } from 'lucide-react';
import { RIDER_LEVEL_RULES, APP_CONFIG } from '../constants'; // Import APP_CONFIG
import { AdminUserModal } from './AdminUserModal';

interface AdminDashboardProps {
  balance: number;
  transactions: Transaction[];
  onWithdraw: () => void;
  users: UserProfile[];
  onVerifyUser: (userId: string) => void;
  proFeedbacks: ProFeedback[];
  clientReviews: ClientReview[];
  internshipRequests?: InternshipRequest[];
  onUpdateInternshipStatus?: (id: string, status: InternshipStatus, companyName?: string) => void;
}

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
    balance, transactions, onWithdraw, users, onVerifyUser, proFeedbacks, clientReviews,
    internshipRequests = [], onUpdateInternshipStatus
}) => {
  // AJOUT DE L'ONGLET 'BETA'
  const [activeTab, setActiveTab] = useState<'FINANCE' | 'USERS' | 'KYC' | 'FEEDBACK_PRO' | 'REVIEWS_CLIENT' | 'STAGES' | 'BETA'>('FINANCE');
  const [selectedUser, setSelectedUser] = useState<UserProfile | null>(null);

  // BETA TEST STATE
  const [testResult, setTestResult] = useState<string | null>(null);

  // Get Current Admin User (Simulated context by finding the admin in users array for UI logic, though in real app currentUser prop is safer)
  // We assume the logged-in user viewing this IS an admin because of parent route protection.
  // We check if "an admin with beta access exists" to show the tab, or better: 
  // In a real app, we check `currentUser.canAccessBeta`. Here we check if the feature is globally enabled.
  const showBetaTab = APP_CONFIG.enableBetaTests; 

  const commissionTransactions = transactions.filter(t => t.type === 'COMMISSION');
  const unverifiedUsers = users.filter(u => !u.verified && u.role === 'PROVIDER');

  const getUserReviews = (userId: string) => {
    return clientReviews.filter(r => r.providerId === userId);
  };
  const getUserFeedbacks = (userId: string) => {
    return proFeedbacks.filter(f => f.providerId === userId);
  };

  // Simulation des tests Backend
  const runBetaTest = (type: 'ping' | 'sandbox') => {
      setTestResult(null);
      setTimeout(() => {
          if (type === 'ping') {
              setTestResult(JSON.stringify({ ok: true, timestamp: new Date().toISOString() }, null, 2));
          } else {
              setTestResult("Sandbox Environment Initialized. Ready for testing new features.");
          }
      }, 800);
  };

  // Enhanced CV Viewer with Error Handling
  const handleViewCV = (url: string) => {
      if (!url || url === '#' || url === '') {
          alert("CV non disponible. L'étudiant n'a pas téléversé de fichier valide.");
      } else {
          // Open in new tab
          const win = window.open(url, '_blank');
          if (!win) alert("Le navigateur a bloqué l'ouverture du CV. Veuillez autoriser les popups.");
      }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 bg-gray-50 min-h-screen">
      <div className="mb-8 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-extrabold text-gray-900 flex items-center gap-3">
            <Building2 className="text-brand-orange" size={32} />
            Administration APNET
          </h1>
          <p className="text-gray-600 mt-1">Gestion centralisée de la plateforme.</p>
        </div>
        <div className="flex bg-white rounded-lg p-1 shadow-sm border border-gray-200 overflow-x-auto max-w-full">
          {[
              { id: 'FINANCE', label: 'Finance' },
              { id: 'USERS', label: `Utilisateurs (${users.length})` },
              { id: 'KYC', label: `KYC (${unverifiedUsers.length})` },
              { id: 'FEEDBACK_PRO', label: 'Avis Pros' },
              { id: 'REVIEWS_CLIENT', label: 'Notes Clients' },
              { id: 'STAGES', label: `Stages (${internshipRequests.length})` }
          ].map(tab => (
              <button 
