## src/admin/realEstateAdminController.ts

Simulation du contrôleur backend pour la gestion immobilière.

```typescript
import { MOCK_REAL_ESTATE_LISTINGS } from '../constants';
import { RealEstateListing } from '../types';

// Simulation d'une base de données persistante en mémoire
let dbProperties: RealEstateListing[] = [...MOCK_REAL_ESTATE_LISTINGS];

// GET /admin/properties
export const getAllProperties = async (): Promise<RealEstateListing[]> => {
  // Simule un délai réseau
  await new Promise(resolve => setTimeout(resolve, 500));
  return [...dbProperties];
};

// POST /admin/properties/approve
export const approveProperty = async (propertyId: string): Promise<RealEstateListing | null> => {
  await new Promise(resolve => setTimeout(resolve, 500));
  const index = dbProperties.findIndex(p => p.id === propertyId);
  if (index !== -1) {
    dbProperties[index] = { ...dbProperties[index], status: 'APPROVED' };
    return dbProperties[index];
  }
  return null;
};

// POST /admin/properties/reject
export const rejectProperty = async (propertyId: string): Promise<RealEstateListing | null> => {
  await new Promise(resolve => setTimeout(resolve, 500));
  const index = dbProperties.findIndex(p => p.id === propertyId);
  if (index !== -1) {
    dbProperties[index] = { ...dbProperties[index], status: 'REJECTED' };
    return dbProperties[index];
  }
  return null;
};

// DELETE /admin/properties/delete/:id
export const deleteProperty = async (propertyId: string): Promise<boolean> => {
  await new Promise(resolve => setTimeout(resolve, 500));
  const initialLength = dbProperties.length;
  dbProperties = dbProperties.filter(p => p.id !== propertyId);
  return dbProperties.length < initialLength;
};
